import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer';
import { HighLowModuleParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/HighLowModuleParser';

export class HighLowModuleEvent extends MessageEvent implements IMessageEvent {
    constructor(callBack: (event: HighLowModuleEvent) => void) {
        super(callBack, HighLowModuleParser);
    }

    public getParser(): HighLowModuleParser {
        return this.parser as HighLowModuleParser;
    }
}
